package main.rice.concisegen;

import main.rice.test.TestCase;
import main.rice.test.TestResults;
import java.util.*;

/**
 * A generator that selects a minimal set of test cases that cover all failing
 * implementations using a greedy set cover algorithm.
 */
public class ConciseSetGenerator {

    /**
     * Finds a minimal set of test cases that covers all failing implementations.
     * Uses a greedy algorithm: repeatedly select the test case that covers the
     * most uncovered failing implementations until all are covered.
     *
     * Does not mutate the input TestResults object.
     *
     * @param results the test results containing test cases and coverage information
     * @return a list of TestCase objects that form a minimal covering set
     */
    public static List<TestCase> setCover(TestResults results) {
        List<TestCase> result = new ArrayList<>();

        // Create copies to avoid mutating the input
        Set<Integer> uncoveredFiles = new HashSet<>(results.getWrongSet());
        List<Set<Integer>> caseToFilesCopy = new ArrayList<>();
        for (Set<Integer> s : results.getCaseToFiles()) {
            caseToFilesCopy.add(new HashSet<>(s));
        }

        // Greedy algorithm: repeatedly pick the test case that covers the most uncovered files
        while (!uncoveredFiles.isEmpty()) {
            int bestCaseIndex = -1;
            int maxCoverage = 0;
            Set<Integer> bestCoverage = new HashSet<>();

            // Find the test case that covers the most uncovered files
            for (int i = 0; i < caseToFilesCopy.size(); i++) {
                Set<Integer> filesToCover = new HashSet<>(caseToFilesCopy.get(i));
                filesToCover.retainAll(uncoveredFiles);

                if (filesToCover.size() > maxCoverage) {
                    maxCoverage = filesToCover.size();
                    bestCaseIndex = i;
                    bestCoverage = filesToCover;
                }
            }

            // If no more uncovered files can be covered, break
            if (bestCaseIndex == -1) {
                break;
            }

            // Add the best test case to result
            result.add(results.getTestCase(bestCaseIndex));

            // Remove covered files from uncovered set
            uncoveredFiles.removeAll(bestCoverage);
        }

        return result;
    }
}

package main.rice.node;

import main.rice.obj.PyFloatObj;
import java.util.HashSet;
import java.util.Random;
import java.util.Set;

/**
 * A node that generates Python float objects.
 * The exhaustive and random domains are lists of integers representing indices
 * into a float range.
 */
public class PyFloatNode extends APyNode<Double, PyFloatObj> {

    /**
     * Random number generator for random value generation.
     */
    private static final Random random = new Random();

    /**
     * Generates all exhaustive float values based on the exhaustive domain.
     *
     * @return a set of all floats in the exhaustive domain as PyFloatObj
     */
    @Override
    public Set<PyFloatObj> genExVals() {
        Set<PyFloatObj> result = new HashSet<>();
        for (Double val : this.exDomain) {
            result.add(new PyFloatObj(val));
        }
        return result;
    }

    /**
     * Generates a single random float value based on the random domain.
     *
     * @return a randomly selected float from the random domain as PyFloatObj
     */
    @Override
    public PyFloatObj genRandVal() {
        int idx = random.nextInt(this.ranDomain.size());
        return new PyFloatObj(this.ranDomain.get(idx));
    }
}

