package main.rice.node;

import main.rice.obj.APyObj;
import java.util.List;
import java.util.Set;

/**
 * An abstract class representing a node that can generate Python objects.
 * Each node can generate exhaustive values (all possible values in a domain)
 * or random values (random samples from a domain).
 *
 * @param <DomainType> the type of values in the domain (Integer, Double, etc.)
 * @param <ValueType> the type of Python object this node generates
 */
public abstract class APyNode<DomainType, ValueType extends APyObj> {

    /**
     * The exhaustive domain - a list of domain values representing configuration
     * for exhaustive value generation.
     */
    protected List<DomainType> exDomain;

    /**
     * The random domain - a list of domain values representing configuration
     * for random value generation.
     */
    protected List<DomainType> ranDomain;

    /**
     * Gets the exhaustive domain for this node.
     *
     * @return the exhaustive domain for this node
     */
    public List<DomainType> getExDomain() {
        return this.exDomain;
    }

    /**
     * Sets the exhaustive domain for this node.
     *
     * @param exDomain the exhaustive domain for this node
     */
    public void setExDomain(List<DomainType> exDomain) {
        this.exDomain = exDomain;
    }

    /**
     * Gets the random domain for this node.
     *
     * @return the random domain for this node
     */
    public List<DomainType> getRanDomain() {
        return this.ranDomain;
    }

    /**
     * Sets the random domain for this node.
     *
     * @param ranDomain the random domain for this node
     */
    public void setRanDomain(List<DomainType> ranDomain) {
        this.ranDomain = ranDomain;
    }

    /**
     * Generates all exhaustive values for this node based on the exhaustive domain.
     *
     * @return a set of all exhaustive values
     */
    public abstract Set<ValueType> genExVals();

    /**
     * Generates a single random value for this node based on the random domain.
     *
     * @return a randomly generated value
     */
    public abstract ValueType genRandVal();

    /**
     * Gets the left child node (for nodes with children).
     *
     * @return the left child node, or null if not applicable
     */
    public APyNode<?, ?> getLeftChild() {
        return null;
    }

    /**
     * Gets the right child node (for nodes with two children).
     *
     * @return the right child node, or null if not applicable
     */
    public APyNode<?, ?> getRightChild() {
        return null;
    }
}

package main.rice.node;

import main.rice.obj.PyBoolObj;
import java.util.HashSet;
import java.util.Random;
import java.util.Set;

/**
 * A node that generates Python boolean objects.
 * The exhaustive and random domains are lists of integers where 0 represents false
 * and 1 represents true.
 */
public class PyBoolNode extends APyNode<Integer, PyBoolObj> {

    /**
     * Random number generator for random value generation.
     */
    private static final Random random = new Random();

    /**
     * Generates all exhaustive boolean values based on the exhaustive domain.
     *
     * @return a set of all booleans in the exhaustive domain as PyBoolObj
     */
    @Override
    public Set<PyBoolObj> genExVals() {
        Set<PyBoolObj> result = new HashSet<>();
        for (Integer val : this.exDomain) {
            result.add(new PyBoolObj(val != 0));
        }
        return result;
    }

    /**
     * Generates a single random boolean value based on the random domain.
     *
     * @return a randomly selected boolean from the random domain as PyBoolObj
     */
    @Override
    public PyBoolObj genRandVal() {
        int idx = random.nextInt(this.ranDomain.size());
        return new PyBoolObj(this.ranDomain.get(idx) != 0);
    }
}

